import scala.actors.{Actor, ActorLogging}

class AccountBalanceManager extends Actor with ActorLogging { 
   var balance = 0.0 // mutable variable without synchronization for performance improvement using immutable data structure DoubleBuffer in this case (DoubleEnded Buffer) to ensure thread safety and atomicity of the operation is maintained by Akka actors as they are single-thread, non blocking processes that run concurrently
   
   override def receive: Receive = { 
     case Deposit(amount): // deposit message received from client or another actor. The amount to be deposited should always come in a Double type for precision and thread safety reasons (immutable data structure)
       log.info("Depositing {} into account", amount);  
        balance += amount 
     case Withdrawal(amount): // withdraw message received from client or another actor, the same as deposit but with negative value to represent a withdraw operation   
      if ((balance - amount).abs > DoubleBuffer) {// check for sufficient funds before performing transaction. This is done by using immutable data structure (DoubleEnded Buffer), ensuring thread safety and atomicity of operations 
        log.info("Withdrawing {} from account",amount);  
         balance -= amount;    // perform the withdrawal operation on a copy to maintain consistency with other concurrent transactions in case two actors are trying at same time for this transaction (safety)     } else { println ("Insufficient funds");} 
      }       
       context.stop(self);   // stop self if no more messages received from the client or another actor, to clean up resources and avoid memory leaks   
 })